世界上下文：
{
  "date": "2026-03-19",
  "local_time": "18:10",
  "city": "Seattle",
  "destination_hint": "Downtown Office",
  "scenario_source": "mobile_implicit_cases_zh"
}

可用工具：
[
  {
    "server": "device",
    "tool_name": "schedule.get_next_event",
    "description": "获取日程中的下一个事件，可作为 calendar.get_next_event 的扩展别名。",
    "read_only": true,
    "required_arguments": []
  },
  {
    "server": "device",
    "tool_name": "schedule.list_free_slots",
    "description": "查询某个时间范围内的空闲日程窗口。",
    "read_only": true,
    "required_arguments": [
      "start_time",
      "end_time"
    ]
  },
  {
    "server": "device",
    "tool_name": "events.get_venue_details",
    "description": "获取活动场馆地址、入场建议和开始时间等信息。",
    "read_only": true,
    "required_arguments": [
      "event_name"
    ]
  },
  {
    "server": "device",
    "tool_name": "weather.get_forecast",
